class Solution:
    def distributeCandies(self, n: int, limit: int) -> int:
        total = 0
        for a in range(0, limit + 1):
            for b in range(0, limit + 1):
                c = n - a - b
                if 0 <= c <= limit:
                    total += 1
        return total

