class Solution:
    def distributeCandies(self, n: int, limit: int) -> int:
        count = 0
        for a in range(0, min(n, limit) + 1):
            rem = n - a
            lo = max(0, rem - limit)
            hi = min(limit, rem)
            if hi >= lo:
                count += hi - lo + 1
        return count

