var distributeCandies = function(n, limit) {
    let count = 0;
    const capA = Math.min(n, limit);
    for (let a = 0; a <= capA; a++) {
        const rem = n - a;
        const lo = Math.max(0, rem - limit);
        const hi = Math.min(limit, rem);
        if (hi >= lo) count += hi - lo + 1;
    }
    return count;
};
